var thiefRats = function(){
  return (flip()? true: false)
}

var lenient = 6

var thief = Infer({}, function(){
  var otherThiefRats = thiefRats();
  var IRat = thiefRats();
  var years = (otherThiefRats? 
              (IRat? lenient : 10) : 
              (IRat? lenient : 0));
  var percentYearsFreedom = (10-years)/10
  factor(percentYearsFreedom)
  return(IRat)
})

