var fallingLeafWithPossibleUpdraft = function(x, y) {
  if (y <= 0) {
    // we are on the ground
    return x
  } else {
    // the x and y change by a random amount
    var xDelta = sample(Gaussian({"mu": 0, "sigma": 2}))
